// TypeScript implementation for Non-Null Assertion
interface NonNullAssertionPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processNonNullAssertion(item: NonNullAssertionPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processNonNullAssertion({ id: 1, title: 'Non-Null Assertion', status: 'active' }));

